	CreateHostFirewallRule(context.Context, *CreateHostFirewallRuleRequest) (*FirewallRule, error)
	ListHostFirewallRules(context.Context, *ListHostFirewallRulesRequest) (*ListHostFirewallRulesResponse, error)
	DeleteHostFirewallRule(context.Context, *DeleteHostFirewallRuleRequest) (*emptypb.Empty, error)
